import {EmotionSystem} from './EmotionSystem';
import {TouchOptions} from './common/Types';

let tunable = null;
// @if DEBUG
try {
    tunable = require('jibo-tunable');
} catch(e) {
    // No tunable library found, disabling debug
}
// @endif
import parentLog from './log';
export const log = parentLog.createChild('Tunable');

const WIN = 'Jibo Emotion System';

export class TunableDebug {

    static setup(es: EmotionSystem) {
        if (tunable) {
            const T = tunable.Tunable;
            T.getButtonField('Trigger head touch', WIN)
                .events.change.on(() => {
                log.info("button change");
                es.triggerTouch(<TouchOptions>{type: 'HEAD_RIGHT'});
            });
        }
    }
}
